import{_ as n,C as a,o as i,c as d,j as e,E as r,a as l,a3 as s}from"./chunks/framework.DACwFHq9.js";const q=JSON.parse('{"title":"上下文管道 (Context Pipeline)","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/settings/context-pipeline.md","filePath":"user-guide/tools/llm-chat/settings/context-pipeline.md","lastUpdated":1779075260000}'),g={name:"user-guide/tools/llm-chat/settings/context-pipeline.md"},h={id:"上下文管道-context-pipeline",tabindex:"-1"};function u(c,t,x,b,f,y){const o=a("LIcon");return i(),d("div",null,[e("h1",h,[r(o,{name:"Network",size:"28"}),t[0]||(t[0]=l(" 上下文管道 (Context Pipeline) ",-1)),t[1]||(t[1]=e("a",{class:"header-anchor",href:"#上下文管道-context-pipeline","aria-label":'Permalink to "<LIcon name="Network" size="28" /> 上下文管道 (Context Pipeline)"'},"​",-1))]),t[8]||(t[8]=e("p",null,[l("上下文管道是 LLM Chat 的"),e("strong",null,"核心数据处理引擎"),l("。每当你发送一条消息时，对话历史、智能体预设、世界书条目、知识库片段、会话变量及附件，都会流经这条精心编排的处理器流水线——最终组装成模型可理解的最优上下文。")],-1)),t[9]||(t[9]=e("p",null,[l("这里的设置面板允许你"),e("strong",null,"可视化地管理整条管道"),l('：调整处理器的执行顺序、启用或禁用特定处理器，从而精细控制"模型到底看到了什么"。')],-1)),t[10]||(t[10]=e("hr",null,null,-1)),t[11]||(t[11]=e("h2",{id:"界面操作",tabindex:"-1"},[l("界面操作 "),e("a",{class:"header-anchor",href:"#界面操作","aria-label":'Permalink to "界面操作"'},"​")],-1)),t[12]||(t[12]=e("h3",{id:"拖拽排序",tabindex:"-1"},[l("拖拽排序 "),e("a",{class:"header-anchor",href:"#拖拽排序","aria-label":'Permalink to "拖拽排序"'},"​")],-1)),e("p",null,[t[2]||(t[2]=l("每个处理器左侧有一个 ",-1)),r(o,{name:"Rank",size:"14"}),t[3]||(t[3]=l(" 拖拽手柄。按住并上下拖动即可改变处理器的执行顺序。",-1))]),t[13]||(t[13]=s('<ul><li><strong>顺序 = 优先级</strong>：列表中越靠上的处理器越先执行。</li><li><strong>自动保存</strong>：松手后顺序会立即持久化，无需手动确认。</li></ul><h3 id="启用-禁用" tabindex="-1">启用 / 禁用 <a class="header-anchor" href="#启用-禁用" aria-label="Permalink to &quot;启用 / 禁用&quot;">​</a></h3><p>每个处理器右侧有一个开关，用于控制是否参与管道执行。</p><ul><li><strong>核心处理器</strong>：部分标记为&quot;核心&quot;的处理器（如会话加载器、异步任务处理器）不可禁用——它们保障了最基础的对话功能。</li><li><strong>按需关闭</strong>：如果你不使用世界书或知识库，可以关闭对应处理器以略微提升响应速度。</li></ul><h3 id="重置为默认" tabindex="-1">重置为默认 <a class="header-anchor" href="#重置为默认" aria-label="Permalink to &quot;重置为默认&quot;">​</a></h3>',5)),e("p",null,[t[4]||(t[4]=l("点击右上角的 ",-1)),r(o,{name:"Refresh",size:"14"}),t[5]||(t[5]=l()),t[6]||(t[6]=e("strong",null,"重置为默认",-1)),t[7]||(t[7]=l(" 按钮，可一键恢复系统推荐的处理器顺序和启用状态。",-1))]),t[14]||(t[14]=s('<div class="warning custom-block"><p class="custom-block-title">注意</p><p>重置操作<strong>不可撤销</strong>，执行前会弹窗确认。如果你精心调整过管道顺序，建议先记录当前配置。</p></div><hr><h2 id="处理器详解" tabindex="-1">处理器详解 <a class="header-anchor" href="#处理器详解" aria-label="Permalink to &quot;处理器详解&quot;">​</a></h2><p>以下按<strong>默认执行顺序</strong>逐一介绍每个内置处理器。</p><h3 id="_1-会话加载器-session-loader" tabindex="-1">1. 会话加载器 (Session Loader) <a class="header-anchor" href="#_1-会话加载器-session-loader" aria-label="Permalink to &quot;1. 会话加载器 (Session Loader)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">值</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>默认优先级</strong></td><td style="text-align:left;">100（最先执行）</td></tr><tr><td style="text-align:left;"><strong>类型</strong></td><td style="text-align:left;">核心（不可禁用）</td></tr></tbody></table><ul><li><strong>作用</strong>：从会话的树状结构中提取当前活动分支的线性历史记录，并转换为管道可处理的&quot;中间格式消息&quot;。</li><li><strong>为什么最先执行</strong>：它是管道的起点，负责为后续所有处理器提供原始消息数据。</li><li><strong>关键能力</strong>： <ul><li><strong>压缩感知</strong>：已被<a href="./../context-pipeline/context-compression">上下文压缩</a>的节点会被自动隐藏，不会重复出现在上下文中。</li><li><strong>HTML → Markdown 转换</strong>：对于较旧的消息（超出最近 N 条），如果开启了优化选项，会自动将富文本转换为 Markdown 以节省 Token。</li><li><strong>Tool 角色转换</strong>：可配置将 <code>tool</code> 角色消息转为 <code>user</code> 角色，兼容不支持 tool 角色的模型。</li></ul></li></ul><hr><h3 id="_2-异步任务处理器" tabindex="-1">2. 异步任务处理器 <a class="header-anchor" href="#_2-异步任务处理器" aria-label="Permalink to &quot;2. 异步任务处理器&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">值</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>默认优先级</strong></td><td style="text-align:left;">110</td></tr><tr><td style="text-align:left;"><strong>类型</strong></td><td style="text-align:left;">核心</td></tr></tbody></table><ul><li><strong>作用</strong>：检测上下文中由 <a href="./../../tool-calling">工具调用</a> 产生的异步任务节点，从任务状态存储中获取最新进度或结果，动态替换节点内容。</li><li><strong>典型场景</strong>：当你让 AI 执行一个耗时操作（如文件转换、网络请求），该处理器会在下一轮对话时自动将&quot;任务运行中 / 已完成 / 已失败&quot;的最新状态注入上下文，让模型感知后续任务进展。</li><li><strong>为什么紧随其后</strong>：它修改的是原始节点内容，必须在消息加载后、后续所有文本处理（正则、Token 计算等）之前完成替换。</li></ul><hr><h3 id="_3-正则处理器-regex-processor" tabindex="-1">3. 正则处理器 (Regex Processor) <a class="header-anchor" href="#_3-正则处理器-regex-processor" aria-label="Permalink to &quot;3. 正则处理器 (Regex Processor)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">值</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>默认优先级</strong></td><td style="text-align:left;">200</td></tr><tr><td style="text-align:left;"><strong>类型</strong></td><td style="text-align:left;">可选</td></tr></tbody></table><ul><li><strong>作用</strong>：对历史消息内容执行正则替换规则。规则来源于三个层级：<strong>全局设置</strong> → <strong>智能体配置</strong> → <strong>用户档案</strong>，优先级由低到高。</li><li><strong>关键能力</strong>： <ul><li><strong>角色过滤</strong>：规则可以限定只对特定角色（user / assistant / system）的消息生效。</li><li><strong>深度限制</strong>：规则可以设定深度范围，例如&quot;只对最近 5 条消息生效&quot;。</li><li><strong>应用阶段</strong>：规则区分&quot;渲染阶段&quot;和&quot;请求阶段&quot;，此处理器仅执行标记为&quot;请求阶段&quot;的规则。</li></ul></li><li><strong>典型用途</strong>：清洗模型幻觉输出、移除不想发送给 API 的特殊标记、格式化特定模板。</li></ul><div class="tip custom-block"><p class="custom-block-title">顺序建议</p><p>默认将正则放在世界书之前，可确保关键词匹配基于清洗后的文本。如果你希望正则也能处理世界书注入的内容，可将其拖到世界书之后。</p></div><hr><h3 id="_4-转写与文本提取器-transcription-processor" tabindex="-1">4. 转写与文本提取器 (Transcription Processor) <a class="header-anchor" href="#_4-转写与文本提取器-transcription-processor" aria-label="Permalink to &quot;4. 转写与文本提取器 (Transcription Processor)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">值</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>默认优先级</strong></td><td style="text-align:left;">250</td></tr><tr><td style="text-align:left;"><strong>类型</strong></td><td style="text-align:left;">可选</td></tr></tbody></table><ul><li><strong>作用</strong>：将消息中的音频/视频附件转写为文本，将文本类附件（如 <code>.txt</code>、<code>.md</code>）的内容读取并插入消息体，使其参与后续 Token 计算。</li><li><strong>关键能力</strong>： <ul><li><strong>占位符替换</strong>：支持 <code>【file::assetId】</code> 占位符语法，转写结果会精准替换对应位置。</li><li><strong>智能回退</strong>：如果附件无法转写（如纯图片），会标注序号标签供多模态模型使用，原始附件保留。</li><li><strong>强制转写策略</strong>：可配置在较旧的消息中强制将媒体转写为文本（节省多模态 Token）。</li></ul></li><li><strong>为什么在 Token 限制器之前</strong>：只有先将附件转为文本，后续限制器才能准确计算实际 Token 占用。</li></ul><hr><h3 id="_5-世界书处理器-worldbook-processor" tabindex="-1">5. 世界书处理器 (Worldbook Processor) <a class="header-anchor" href="#_5-世界书处理器-worldbook-processor" aria-label="Permalink to &quot;5. 世界书处理器 (Worldbook Processor)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">值</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>默认优先级</strong></td><td style="text-align:left;">300</td></tr><tr><td style="text-align:left;"><strong>类型</strong></td><td style="text-align:left;">可选</td></tr></tbody></table><ul><li><strong>作用</strong>：扫描历史消息中的关键词，触发匹配的<a href="./../worldbook/index">世界书</a>条目并注入到上下文中。</li><li><strong>关键能力</strong>： <ul><li><strong>多种激活条件</strong>：Constant（始终激活）、关键词匹配、Delay（历史不足 N 条时不激活）、Cooldown（激活后冷却）、Sticky（匹配后持续生效）。</li><li><strong>递归扫描</strong>：已注入的条目内容也会参与关键词匹配，可触发连锁激活。</li><li><strong>包含组竞争</strong>：同一组内的条目按权重竞争，只有&quot;赢家&quot;被注入，防止上下文膨胀。</li><li><strong>位置注入</strong>：支持 BeforeChar、AfterChar、Depth（从末尾倒数）等多种注入位置。</li><li><strong>角色/标签过滤</strong>：条目可限定只对特定智能体或标签生效。</li></ul></li><li><strong>SillyTavern 兼容</strong>：完整兼容 ST 的世界书格式和大部分高级特性。</li></ul><hr><h3 id="_6-注入组装器-injection-assembler" tabindex="-1">6. 注入组装器 (Injection Assembler) <a class="header-anchor" href="#_6-注入组装器-injection-assembler" aria-label="Permalink to &quot;6. 注入组装器 (Injection Assembler)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">值</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>默认优先级</strong></td><td style="text-align:left;">400</td></tr><tr><td style="text-align:left;"><strong>类型</strong></td><td style="text-align:left;">核心</td></tr></tbody></table><div><ul><li><strong>作用</strong>：这是管道中<strong>最核心</strong>的组装步骤。它负责处理智能体预设消息的分类、宏展开，并将预设骨架、深度注入、锚点注入与历史消息进行精密组装。</li><li><strong>关键能力</strong>： <ul><li><strong>消息分类</strong>：预设消息被分为三类——骨架（按数组顺序）、深度注入（按深度值插入历史）、锚点注入（绑定到特定锚点前后）。</li><li><strong>宏处理</strong>：在组装前展开所有 <code>{{宏}}</code> 占位符（如 <code>{{user}}</code>、<code>{{char}}</code>、<code>{{time}}</code>），具体逻辑由内置宏引擎处理。</li><li><strong>高级深度配置</strong>：支持单点 <code>&quot;5&quot;</code>、多点 <code>&quot;3, 10, 15&quot;</code>、循环 <code>&quot;10~5&quot;</code>（从第10条起每5条插入一次）和混合语法。</li><li><strong>模型/渠道匹配</strong>：预设消息可配置正则规则，仅在特定模型或渠道下生效。</li><li><strong>工具宏保底</strong>：如果开启了工具调用但预设中没有 <code>{{tools}}</code> 宏，系统会自动追加一条保底注入。</li></ul></li></ul></div><hr><h3 id="_7-知识库处理器-knowledge-processor" tabindex="-1">7. 知识库处理器 (Knowledge Processor) <a class="header-anchor" href="#_7-知识库处理器-knowledge-processor" aria-label="Permalink to &quot;7. 知识库处理器 (Knowledge Processor)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">值</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>默认优先级</strong></td><td style="text-align:left;">450</td></tr><tr><td style="text-align:left;"><strong>类型</strong></td><td style="text-align:left;">可选</td></tr></tbody></table><ul><li><strong>作用</strong>：扫描消息中的 <code>【kb】</code> 或 <code>【knowledge】</code> 占位符，执行 RAG 检索，将匹配的知识片段替换到占位符位置。</li><li><strong>关键能力</strong>： <ul><li><strong>多种激活模式</strong>：<code>always</code>（每轮激活）、<code>gate</code>（关键词门控）、<code>turn</code>（每 N 轮激活）、<code>static</code>（静态加载指定条目）。</li><li><strong>参数化占位符</strong>：<code>【kb::库名::数量::最低分::模式::参数】</code>，支持精细控制每个检索点的行为。</li><li><strong>查询预处理</strong>：自动清洗、分词、停用词过滤和标签匹配。</li><li><strong>精确文本缓存</strong>：采用精确文本匹配策略（完全一致才命中），适用于同轮多占位符和重试场景。</li><li><strong>独立检索</strong>：每次检索独立执行，不混入历史结果。分数阈值作为主要截断依据。</li></ul></li><li><strong>为什么在注入组装器之后</strong>：占位符通常存在于预设消息中，必须等注入组装器完成骨架组装后才能扫描到。</li></ul><div class="info custom-block"><p class="custom-block-title">了解更多</p><p>知识库处理器的完整配置选项（引擎选择、缓存策略、模板定制等）请参阅 <strong><a href="./../context-pipeline/knowledge-processor">RAG 知识库检索配置</a></strong>。</p></div><hr><h3 id="_8-会话变量处理器-variable-processor" tabindex="-1">8. 会话变量处理器 (Variable Processor) <a class="header-anchor" href="#_8-会话变量处理器-variable-processor" aria-label="Permalink to &quot;8. 会话变量处理器 (Variable Processor)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">值</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>默认优先级</strong></td><td style="text-align:left;">500</td></tr><tr><td style="text-align:left;"><strong>类型</strong></td><td style="text-align:left;">可选</td></tr></tbody></table><ul><li><strong>作用</strong>：解析消息中的 <code>&lt;svar&gt;</code> 标签，维护变量的状态快照，并执行 <code>$[...]</code> 内置替换符的动态渲染。</li><li><strong>关键能力</strong>： <ul><li><strong>标签语法</strong>：<code>&lt;svar name=&quot;hp&quot; op=&quot;+&quot; value=&quot;10&quot; /&gt;</code> —— 对变量执行加减乘除或赋值操作。</li><li><strong>快照回溯</strong>：从最新消息往回查找最近的变量快照作为计算起点，确保分支切换后状态正确。</li><li><strong>边界约束</strong>：变量定义中可设置 <code>min</code> / <code>max</code>，运算结果会自动钳制到合法范围。</li><li><strong>格式化输出</strong>：支持 <code>$[svars::table]</code> 将所有可见变量渲染为表格，<code>$[svars::list]</code> 渲染为列表。</li></ul></li><li><strong>为什么在 Token 限制器之前</strong>：替换后的变量内容需要参与 Token 计算，否则预算不准确。</li></ul><hr><h3 id="_9-token-限制器-token-limiter" tabindex="-1">9. Token 限制器 (Token Limiter) <a class="header-anchor" href="#_9-token-限制器-token-limiter" aria-label="Permalink to &quot;9. Token 限制器 (Token Limiter)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">值</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>默认优先级</strong></td><td style="text-align:left;">600</td></tr><tr><td style="text-align:left;"><strong>类型</strong></td><td style="text-align:left;">核心</td></tr></tbody></table><ul><li><strong>作用</strong>：根据智能体配置的&quot;最大上下文 Token&quot;预算，从历史消息中截断超出部分，确保最终发送的上下文不超标。</li><li><strong>关键能力</strong>： <ul><li><strong>预设优先</strong>：先计算所有预设/注入消息的 Token 占用，剩余预算全部分配给历史消息。</li><li><strong>从新到旧保留</strong>：保留最新的历史消息，截断最旧的部分。</li><li><strong>部分截断保留开头</strong>：可配置被截断消息保留前 N 个字符（附加&quot;…(已截断)&quot;标记），而非完全丢弃。</li><li><strong>附件 Token 计算</strong>：图片等附件也会计入 Token 预算（按模型定义的图片 Token 消耗）。</li><li><strong>统计信息输出</strong>：处理完成后会在共享黑板中记录截断前后的 Token 和字符数变化，供<a href="./../context-pipeline/analyzer">上下文分析器</a>展示。</li></ul></li></ul><div class="danger custom-block"><p class="custom-block-title">关键顺序约束</p><p>Token 限制器<strong>必须</strong>在注入组装器和变量处理器之后执行。只有当所有内容（预设、知识库、变量替换）都已注入完毕，限制器才能准确计算总 Token 占用并精准截断。</p></div><hr><h3 id="_10-消息格式化器-message-formatter" tabindex="-1">10. 消息格式化器 (Message Formatter) <a class="header-anchor" href="#_10-消息格式化器-message-formatter" aria-label="Permalink to &quot;10. 消息格式化器 (Message Formatter)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">值</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>默认优先级</strong></td><td style="text-align:left;">800</td></tr><tr><td style="text-align:left;"><strong>类型</strong></td><td style="text-align:left;">可选</td></tr></tbody></table><ul><li><p><strong>作用</strong>：在发送前应用模型特定的消息结构规则，确保请求格式符合不同厂商 API 的要求。</p></li><li><p><strong>包含四个子规则</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">子规则</th><th style="text-align:left;">默认状态</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">合并 System 到头部</td><td style="text-align:left;">✅ 启用</td><td style="text-align:left;">将分散的 system 消息合并为一条</td></tr><tr><td style="text-align:left;">合并连续相同角色</td><td style="text-align:left;">✅ 启用</td><td style="text-align:left;">将相邻同角色消息合并（如两条连续的 user）</td></tr><tr><td style="text-align:left;">转换 System 为 User</td><td style="text-align:left;">❌ 禁用</td><td style="text-align:left;">适用于不支持 system 角色的模型</td></tr><tr><td style="text-align:left;">确保角色交替</td><td style="text-align:left;">❌ 禁用</td><td style="text-align:left;">在连续同角色间插入占位符，强制 user/assistant 交替</td></tr></tbody></table></li><li><p><strong>配置合并策略</strong>：默认状态 → 模型定义覆盖 → 智能体配置覆盖。</p></li><li><p><strong>典型场景</strong>：Claude 模型要求 user/assistant 严格交替；某些本地模型不支持 system 角色。</p></li></ul><hr><h3 id="_11-base64-资源解析器-asset-resolver" tabindex="-1">11. Base64 资源解析器 (Asset Resolver) <a class="header-anchor" href="#_11-base64-资源解析器-asset-resolver" aria-label="Permalink to &quot;11. Base64 资源解析器 (Asset Resolver)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">值</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>默认优先级</strong></td><td style="text-align:left;">10000（最后执行）</td></tr><tr><td style="text-align:left;"><strong>类型</strong></td><td style="text-align:left;">核心</td></tr></tbody></table><ul><li><strong>作用</strong>：管道的<strong>最后一步</strong>。将剩余的二进制附件引用（图片、文档、音视频）转换为模型 API 可接受的最终格式。</li><li><strong>关键能力</strong>： <ul><li><strong>按模型能力适配</strong>：根据模型是否支持视觉、原生 PDF 等能力，选择合适的发送格式。</li><li><strong>PDF 智能转换</strong>：如果模型不支持原生 PDF 但支持图片，自动将 PDF 渲染为图片序列。</li><li><strong>容错处理</strong>：单个附件转换失败不会中断其他附件的处理。</li></ul></li><li><strong>为什么最后执行</strong>：Base64 编码后的数据体积极大，如果在前面步骤就转换，会严重拖慢正则匹配、Token 计算等文本处理操作。</li></ul><hr><h2 id="为什么顺序很重要" tabindex="-1">为什么顺序很重要？ <a class="header-anchor" href="#为什么顺序很重要" aria-label="Permalink to &quot;为什么顺序很重要？&quot;">​</a></h2><p>管道的编排顺序直接影响<strong>数据的可见性</strong>和<strong>计算的准确性</strong>。以下是几个关键的顺序依赖关系：</p><h3 id="正则-vs-世界书" tabindex="-1">正则 vs 世界书 <a class="header-anchor" href="#正则-vs-世界书" aria-label="Permalink to &quot;正则 vs 世界书&quot;">​</a></h3><ul><li><strong>默认：正则在前</strong> → 确保世界书扫描的是清洗后的文本。</li><li><strong>如果反转</strong> → 正则也能修改世界书注入的内容（适合需要统一清洗所有内容的场景）。</li></ul><h3 id="注入组装-变量-→-token-限制" tabindex="-1">注入组装 + 变量 → Token 限制 <a class="header-anchor" href="#注入组装-变量-→-token-限制" aria-label="Permalink to &quot;注入组装 + 变量 → Token 限制&quot;">​</a></h3><p>这是<strong>硬性约束</strong>。限制器必须看到完整的最终内容才能准确计算。如果把限制器放到组装器前面，预设消息的 Token 占用不会被计入预算，导致实际发送的上下文超标或历史被过度截断。</p><h3 id="资源解析必须最后" tabindex="-1">资源解析必须最后 <a class="header-anchor" href="#资源解析必须最后" aria-label="Permalink to &quot;资源解析必须最后&quot;">​</a></h3><p>Base64 数据不参与任何文本逻辑（正则、关键词匹配、Token 计数都基于原始文本完成），所以必须延迟到一切文本处理结束后才转换，这也是为什么它的优先级被设为 10000。</p><hr><h2 id="常见操作场景" tabindex="-1">常见操作场景 <a class="header-anchor" href="#常见操作场景" aria-label="Permalink to &quot;常见操作场景&quot;">​</a></h2><h3 id="我不用世界书和知识库-想提速" tabindex="-1">&quot;我不用世界书和知识库，想提速&quot; <a class="header-anchor" href="#我不用世界书和知识库-想提速" aria-label="Permalink to &quot;&quot;我不用世界书和知识库，想提速&quot;&quot;">​</a></h3><p>关闭<strong>世界书处理器</strong>和<strong>知识库处理器</strong>的开关即可。管道会跳过这两步，减少不必要的扫描。</p><h3 id="我想让正则也清洗世界书注入的内容" tabindex="-1">&quot;我想让正则也清洗世界书注入的内容&quot; <a class="header-anchor" href="#我想让正则也清洗世界书注入的内容" aria-label="Permalink to &quot;&quot;我想让正则也清洗世界书注入的内容&quot;&quot;">​</a></h3><p>将<strong>正则处理器</strong>拖到<strong>世界书处理器</strong>的下方。这样正则会在世界书注入完成后才执行。</p><h3 id="模型报错说消息格式不对" tabindex="-1">&quot;模型报错说消息格式不对&quot; <a class="header-anchor" href="#模型报错说消息格式不对" aria-label="Permalink to &quot;&quot;模型报错说消息格式不对&quot;&quot;">​</a></h3><p>启用消息格式化器中的对应子规则。例如：</p><ul><li>报 &quot;user messages must alternate&quot; → 启用&quot;确保角色交替&quot;</li><li>报 &quot;system role not supported&quot; → 启用&quot;转换 System 为 User&quot;</li></ul><h3 id="上下文好像总是超长" tabindex="-1">&quot;上下文好像总是超长&quot; <a class="header-anchor" href="#上下文好像总是超长" aria-label="Permalink to &quot;&quot;上下文好像总是超长&quot;&quot;">​</a></h3><p>检查 Token 限制器是否被禁用或排在了注入组装器之前。确保它在列表中位于所有注入类处理器的<strong>下方</strong>。</p><hr><div class="info custom-block"><p class="custom-block-title">进阶阅读</p><ul><li><strong><a href="./../context-pipeline/index">上下文管道概览</a></strong> — 管道的设计理念和分类总览</li><li><strong><a href="./../context-pipeline/processors">处理器详解与执行顺序</a></strong> — 每个处理器的深入解析</li><li><strong><a href="./../context-pipeline/analyzer">上下文分析器</a></strong> — 实时观察管道的输入与输出</li><li><strong><a href="./../context-pipeline/token-management">Token 预算管理</a></strong> — Token 限制器的完整配置选项</li></ul></div>',72))])}const k=n(g,[["render",u]]);export{q as __pageData,k as default};
